import { Component, OnInit } from '@angular/core';
import { Router, RouterLink } from '@angular/router';
import { BaseChartDirective, provideCharts, withDefaultRegisterables } from 'ng2-charts';
import { MatIconModule } from '@angular/material/icon';
import { CurrencyFormatPipe } from '../currency-format.pipe';
import { ApiService } from '../api.service';

export interface ChartDataset {
  label: string;
  data: number[];
}

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [BaseChartDirective, CurrencyFormatPipe, RouterLink, MatIconModule],
  providers: [provideCharts(withDefaultRegisterables())],
  templateUrl: './dashboard.component.html',
  styleUrl: './dashboard.component.scss',
})
export class DashboardComponent implements OnInit {
  totalObligated = 0;
  largestAgency: { name: string; totalCents: number } | null = null;
  coverageGapCount = 0;
  lastSync: string | null = null;

  chartLabels: string[] = [];
  chartDatasets: ChartDataset[] = [];
  chartAgencyIds: number[] = [];

  private agencies: Array<{ id: number; name: string; totalCents: number }> = [];

  private static readonly TOP_N = 5;

  constructor(
    private readonly api: ApiService,
    private readonly router: Router,
  ) {}

  ngOnInit(): void {
    this.api.getAgencies().subscribe(
      agencies => {
        this.agencies = agencies;
        this.totalObligated = agencies.reduce((sum, a) => sum + a.totalCents, 0);
        const largest = agencies.reduce<{ name: string; totalCents: number } | null>(
          (best, a) => (!best || a.totalCents > best.totalCents ? a : best),
          null,
        );
        this.largestAgency = largest ? { name: largest.name, totalCents: largest.totalCents } : null;
        this.buildChart(this.agencies);
      },
    );

    this.api.getDisasterRecoveryRatios({}).subscribe(
      ratios => {
        const gapStates = new Set(ratios.filter(r => r.recoveryRatio < 0.5).map(r => r.stateCode));
        this.coverageGapCount = gapStates.size;
      },
    );

    this.api.getLastSync().subscribe(
      ts => { this.lastSync = ts; },
    );
  }

  buildChart(agencies: Array<{ id: number; name: string; totalCents: number }>): void {
    const withData = agencies.filter(a => a.totalCents > 0);
    const sorted = [...withData].sort((a, b) => b.totalCents - a.totalCents);
    const top = sorted.slice(0, DashboardComponent.TOP_N);
    const otherTotal = sorted.length > DashboardComponent.TOP_N
      ? sorted.slice(DashboardComponent.TOP_N).reduce((sum, a) => sum + a.totalCents, 0)
      : sorted.reduce((sum, a) => sum + a.totalCents, 0);
    const labels = top.map(a => a.name).concat(['Other']);
    const data = top.map(a => a.totalCents).concat([otherTotal]);
    this.chartLabels = labels;
    this.chartDatasets = [{ label: 'Obligated (cents)', data }];
    this.chartAgencyIds = top.map(a => a.id);
  }

  onChartClick(event: any): void {
    const clicked = event.active[0];
    if (!clicked) return;
    const index = clicked.index;
    if (index < this.chartAgencyIds.length) {
      this.router.navigate(['/agencies', this.chartAgencyIds[index]]);
    }
  }

  onNavClick(route: string, event: Event): void {
    event.preventDefault();
    this.router.navigate([route]);
  }
}

import { ComponentFixture, TestBed, fakeAsync, tick } from '@angular/core/testing';
import { Router, RouterLink, ActivatedRoute } from '@angular/router';
import { MatIconModule } from '@angular/material/icon';
import { of, Subject } from 'rxjs';
import { provideCharts, withDefaultRegisterables } from 'ng2-charts';

import { DashboardComponent } from './dashboard.component';
import { ApiService } from '../api.service';
import { CurrencyFormatPipe } from '../currency-format.pipe';

describe('DashboardComponent', () => {
  let routerSpy: {
    navigate: jest.Mock;
    createUrlTree: jest.Mock;
    serializeUrl: jest.Mock;
    navigateEnd: jest.Mock;
    events: any;
  };
  let apiSpy: {
    getAgencies: jest.Mock;
    getDisasterRecoveryRatios: jest.Mock;
    getLastSync: jest.Mock;
  };

  beforeEach(() => {
    const events$ = new (require('rxjs')).Subject<any>();
    routerSpy = {
      navigate: jest.fn(),
      createUrlTree: jest.fn((links: string[]) => links.length > 0 ? links[0] : '/'),
      serializeUrl: jest.fn((url: string) => ({ toString: () => url })),
      navigateEnd: jest.fn(),
      events: events$,
    };
    apiSpy = {
      getAgencies: jest.fn().mockReturnValue(of([])),
      getDisasterRecoveryRatios: jest.fn().mockReturnValue(of([])),
      getLastSync: jest.fn().mockReturnValue(of(null)),
    };

    TestBed.configureTestingModule({
      imports: [DashboardComponent, CurrencyFormatPipe, RouterLink, MatIconModule],
      providers: [
        { provide: Router, useValue: routerSpy },
        { provide: ApiService, useValue: apiSpy },
        { provide: ActivatedRoute, useValue: { snapshot: { data: {} } } },
        provideCharts(withDefaultRegisterables()),
      ],
    });
  });

  interface CardTestCase {
    name: string;
    agencies: Array<{ id: number; name: string; totalCents: number }>;
    ratios: Array<{ stateCode: string; recoveryRatio: number }>;
    expectedTotal: number;
    expectedLargest: { name: string; totalCents: number } | null;
    expectedGapCount: number;
  }

  const testTable: CardTestCase[] = [
    {
      name: 'computes total obligated across all agencies',
      agencies: [
        { id: 1, name: 'Agency A', totalCents: 100000 },
        { id: 2, name: 'Agency B', totalCents: 200000 },
        { id: 3, name: 'Agency C', totalCents: 300000 },
      ],
      ratios: [],
      expectedTotal: 600000,
      expectedLargest: { name: 'Agency C', totalCents: 300000 },
      expectedGapCount: 0,
    },
    {
      name: 'identifies largest agency by highest totalCents',
      agencies: [
        { id: 1, name: 'Small', totalCents: 50000 },
        { id: 2, name: 'Medium', totalCents: 150000 },
        { id: 3, name: 'Large', totalCents: 500000 },
      ],
      ratios: [],
      expectedTotal: 700000,
      expectedLargest: { name: 'Large', totalCents: 500000 },
      expectedGapCount: 0,
    },
    {
      name: 'counts distinct states with coverage gap ratio below 0.5',
      agencies: [],
      ratios: [
        { stateCode: '06', recoveryRatio: 0.3 },
        { stateCode: '12', recoveryRatio: 0.8 },
        { stateCode: '48', recoveryRatio: 0.2 },
        { stateCode: '06', recoveryRatio: 0.4 },
        { stateCode: '36', recoveryRatio: 1.5 },
      ],
      expectedTotal: 0,
      expectedLargest: null,
      expectedGapCount: 2,
    },
    {
      name: 'handles empty agencies and ratios gracefully',
      agencies: [],
      ratios: [],
      expectedTotal: 0,
      expectedLargest: null,
      expectedGapCount: 0,
    },
  ];

  it.each(testTable)('$name', ({ agencies, ratios, expectedTotal, expectedLargest, expectedGapCount }) => {
    apiSpy.getAgencies.mockReturnValue(of(agencies));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of(ratios));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.totalObligated).toBe(expectedTotal);
    expect(component.largestAgency).toEqual(expectedLargest);
    expect(component.coverageGapCount).toBe(expectedGapCount);
  });

  it('groups 6 agencies into top-5 bars plus Other bar', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
      { id: 3, name: 'Agency C', totalCents: 200000 },
      { id: 4, name: 'Agency D', totalCents: 100000 },
      { id: 5, name: 'Agency E', totalCents: 50000 },
      { id: 6, name: 'Agency F', totalCents: 10000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.chartLabels).toEqual([
      'Agency A', 'Agency B', 'Agency C', 'Agency D', 'Agency E', 'Other',
    ]);
    expect(component.chartDatasets[0].data).toEqual([500000, 300000, 200000, 100000, 50000, 10000]);
    expect(component.chartAgencyIds).toEqual([1, 2, 3, 4, 5]);
    expect(component.chartLabels.length).toBe(6);
  });

  it('shows single Other bar when all agencies have zero spending', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 0 },
      { id: 2, name: 'Agency B', totalCents: 0 },
      { id: 3, name: 'Agency C', totalCents: 0 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.chartLabels).toEqual(['Other']);
    expect(component.chartDatasets[0].data).toEqual([0]);
    expect(component.chartAgencyIds).toEqual([]);
    expect(component.chartLabels.length).toBe(1);
  });

  it('shows fewer bars than TOP_N plus Other when fewer agencies have data', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(component.chartLabels).toEqual(['Agency A', 'Agency B', 'Other']);
    expect(component.chartDatasets[0].data).toEqual([500000, 300000, 800000]);
    expect(component.chartAgencyIds).toEqual([1, 2]);
    expect(component.chartLabels.length).toBe(3);
  });

  it('navigates to top bar agency on chart click', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
      { id: 3, name: 'Agency C', totalCents: 200000 },
      { id: 4, name: 'Agency D', totalCents: 100000 },
      { id: 5, name: 'Agency E', totalCents: 50000 },
      { id: 6, name: 'Agency F', totalCents: 10000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    component.onChartClick({ active: [{ datasetIndex: 0, index: 0 }] });
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/agencies', 1]);

    component.onChartClick({ active: [{ datasetIndex: 0, index: 3 }] });
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/agencies', 4]);
  });

  it('does not navigate when Other bar is clicked', () => {
    apiSpy.getAgencies.mockReturnValue(of([
      { id: 1, name: 'Agency A', totalCents: 500000 },
      { id: 2, name: 'Agency B', totalCents: 300000 },
    ]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    component.onChartClick({ active: [{ datasetIndex: 0, index: 2 }] });
    expect(routerSpy.navigate).not.toHaveBeenCalled();
  });

  it('does nothing on chart click with no active bar', () => {
    apiSpy.getAgencies.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    component.onChartClick({ active: [] });
    expect(routerSpy.navigate).not.toHaveBeenCalled();
  });

  it('fetches agencies, ratios, and last sync on init', () => {
    apiSpy.getAgencies.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));
    apiSpy.getLastSync.mockReturnValue(of('2024-01-15T10:00:00Z'));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    expect(apiSpy.getAgencies).toHaveBeenCalled();
    expect(apiSpy.getDisasterRecoveryRatios).toHaveBeenCalled();
    expect(apiSpy.getLastSync).toHaveBeenCalled();
    expect(component.lastSync).toBe('2024-01-15T10:00:00Z');
  });

  it('renders 3 nav cards with correct routerLink targets', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const cards = fixture.nativeElement.querySelectorAll('.card-body');
    expect(cards.length).toBe(3);

    const links = fixture.nativeElement.querySelectorAll('a[href]');
    expect(links.length).toBe(3);

    const routes = Array.from(links as NodeListOf<Element>).map(l => l.getAttribute('href'));
    expect(routes).toContain('/geography');
    expect(routes).toContain('/agencies');
    expect(routes).toContain('/disaster');
  });

  it('navigates to /geography when geography card is clicked', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const link = fixture.nativeElement.querySelector('.nav-card:nth-child(1)');
    link.dispatchEvent(new Event('click', { bubbles: true }));
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/geography']);
  });

  it('navigates to /agencies when agencies card is clicked', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const link = fixture.nativeElement.querySelector('.nav-card:nth-child(2)');
    link.dispatchEvent(new Event('click', { bubbles: true }));
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/agencies']);
  });

  it('navigates to /disaster when disaster card is clicked', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const link = fixture.nativeElement.querySelector('.nav-card:nth-child(3)');
    link.dispatchEvent(new Event('click', { bubbles: true }));
    expect(routerSpy.navigate).toHaveBeenCalledWith(['/disaster']);
  });

  it('each nav card has title, description, and icon', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const cards = fixture.nativeElement.querySelectorAll('.card-body');
    expect(cards.length).toBe(3);

    for (const card of cards) {
      expect(card.querySelector('h2')).toBeTruthy();
      expect(card.querySelector('p')).toBeTruthy();
      expect(card.parentElement.querySelector('mat-icon')).toBeTruthy();
    }
  });

  it('renders the about paragraph between h1 and nav-cards', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    fixture.detectChanges();

    const h1 = fixture.nativeElement.querySelector('h1');
    expect(h1).toBeTruthy();

    const about = fixture.nativeElement.querySelector('.about');
    expect(about).toBeTruthy();
    expect(about.textContent).toContain('USASpending.gov');
    expect(about.textContent).toContain('OpenFEMA');
    expect(about.textContent).toContain('navigation cards');
    expect(about.textContent).toContain('summary cards');
    expect(about.textContent).toContain('agency chart');

    const navCards = fixture.nativeElement.querySelector('.nav-cards');
    expect(navCards).toBeTruthy();

    // Verify about is between h1 and nav-cards
    const h1Index = Array.from(fixture.nativeElement.childNodes).indexOf(h1);
    const aboutIndex = Array.from(fixture.nativeElement.childNodes).indexOf(about);
    const navCardsIndex = Array.from(fixture.nativeElement.childNodes).indexOf(navCards);
    expect(aboutIndex).toBeGreaterThan(h1Index);
    expect(aboutIndex).toBeLessThan(navCardsIndex);
  });

  it('page load completes in under 2 seconds', fakeAsync(() => {
    apiSpy.getAgencies.mockReturnValue(of([]));
    apiSpy.getDisasterRecoveryRatios.mockReturnValue(of([]));
    apiSpy.getLastSync.mockReturnValue(of(null));

    const fixture = TestBed.createComponent(DashboardComponent);
    const component = fixture.componentInstance;
    const start = Date.now();
    fixture.detectChanges();
    tick(100);
    const elapsed = Date.now() - start;

    expect(elapsed).toBeLessThan(2000);
  }));
});
